// src/pages/AdminDashboard.js
import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import {
  Container,
  Grid,
  Paper,
  Typography,
  Button,
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableRow,
  CircularProgress,
} from "@mui/material";
import { useAuth } from "../contexts/AuthContext";

export default function AdminDashboard() {
  const { auth, logout } = useAuth();
  const navigate = useNavigate();
  const token = auth?.token;

  const [overview, setOverview] = useState(null);
  const [users, setUsers] = useState([]);
  const [captains, setCaptains] = useState([]);
  const [pendingCaptains, setPendingCaptains] = useState([]);
  const [rides, setRides] = useState([]);
  const [loading, setLoading] = useState(true);

  const API_BASE = "http://localhost:5000/api/admin"; // change if needed

  const fetchData = async () => {
    setLoading(true);
    try {
      const headers = { Authorization: `Bearer ${token}` };

      const [overviewRes, usersRes, captainsRes, pendingRes, ridesRes] = await Promise.all([
        fetch(`${API_BASE}/overview`, { headers }),
        fetch(`${API_BASE}/users`, { headers }),
        fetch(`${API_BASE}/captains`, { headers }),
        fetch(`${API_BASE}/pending-captains`, { headers }),
        fetch(`${API_BASE}/rides`, { headers }),
      ]);

      if (!overviewRes.ok) throw new Error("Unauthorized");

      setOverview(await overviewRes.json());
      setUsers((await usersRes.json()).users || []);
      setCaptains((await captainsRes.json()).captains || []);
      setPendingCaptains((await pendingRes.json()).pendingCaptains || []);
      setRides((await ridesRes.json()).rides || []);
    } catch (err) {
      console.error(err);
      logout(); // logout if token invalid
      navigate("/admin");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleApprove = async (id) => {
    await fetch(`${API_BASE}/captain/${id}/approve`, {
      method: "POST",
      headers: { Authorization: `Bearer ${token}` },
    });
    fetchData();
  };

  const handleReject = async (id) => {
    await fetch(`${API_BASE}/captain/${id}/reject`, {
      method: "POST",
      headers: { Authorization: `Bearer ${token}` },
    });
    fetchData();
  };

  if (loading) return <CircularProgress sx={{ display: "block", margin: "50px auto" }} />;

  return (
    <Container maxWidth="xl" sx={{ mt: 4 }}>
      <Typography variant="h4" sx={{ mb: 3, fontWeight: "bold" }}>
        Admin Dashboard
      </Typography>

      <Button variant="contained" color="error" sx={{ mb: 3 }} onClick={() => { logout(); navigate("/admin"); }}>
        Logout
      </Button>

      {/* Overview Cards */}
      <Grid container spacing={3} sx={{ mb: 4 }}>
        {overview &&
          Object.entries(overview).map(([key, value]) => (
            <Grid item xs={12} sm={6} md={2} key={key}>
              <Paper sx={{ p: 2, textAlign: "center" }}>
                <Typography variant="subtitle1" sx={{ textTransform: "capitalize" }}>{key.replace(/([A-Z])/g, ' $1')}</Typography>
                <Typography variant="h5" sx={{ fontWeight: "bold" }}>{value}</Typography>
              </Paper>
            </Grid>
          ))}
      </Grid>

      {/* Users Table */}
      <Typography variant="h6" sx={{ mb: 1 }}>Users</Typography>
      <Paper sx={{ mb: 3 }}>
        <Table>
          <TableHead>
            <TableRow>
              <TableCell>Full Name</TableCell>
              <TableCell>Email</TableCell>
              <TableCell>Mobile</TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {users.length ? users.map(u => (
              <TableRow key={u._id}>
                <TableCell>{u.fullName}</TableCell>
                <TableCell>{u.email}</TableCell>
                <TableCell>{u.mobile}</TableCell>
              </TableRow>
            )) : <TableRow><TableCell colSpan={3}>No users found</TableCell></TableRow>}
          </TableBody>
        </Table>
      </Paper>

      {/* Pending Captains */}
      <Typography variant="h6" sx={{ mb: 1 }}>Pending Captains</Typography>
      <Paper sx={{ mb: 3 }}>
        <Table>
          <TableHead>
            <TableRow>
              <TableCell>Full Name</TableCell>
              <TableCell>Email</TableCell>
              <TableCell>Mobile</TableCell>
              <TableCell>Actions</TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {pendingCaptains.length ? pendingCaptains.map(c => (
              <TableRow key={c._id}>
                <TableCell>{c.fullName}</TableCell>
                <TableCell>{c.email}</TableCell>
                <TableCell>{c.mobile}</TableCell>
                <TableCell>
                  <Button variant="contained" color="success" size="small" sx={{ mr: 1 }} onClick={() => handleApprove(c._id)}>Approve</Button>
                  <Button variant="contained" color="error" size="small" onClick={() => handleReject(c._id)}>Reject</Button>
                </TableCell>
              </TableRow>
            )) : <TableRow><TableCell colSpan={4}>No pending captains</TableCell></TableRow>}
          </TableBody>
        </Table>
      </Paper>

      {/* Rides Table */}
      <Typography variant="h6" sx={{ mb: 1 }}>Rides</Typography>
      <Paper sx={{ mb: 3 }}>
        <Table>
          <TableHead>
            <TableRow>
              <TableCell>Rider</TableCell>
              <TableCell>Captain</TableCell>
              <TableCell>Date</TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {rides.length ? rides.map(r => (
              <TableRow key={r._id}>
                <TableCell>{r.riderId?.fullName}</TableCell>
                <TableCell>{r.captainId?.fullName}</TableCell>
                <TableCell>{new Date(r.createdAt).toLocaleString()}</TableCell>
              </TableRow>
            )) : <TableRow><TableCell colSpan={3}>No rides found</TableCell></TableRow>}
          </TableBody>
        </Table>
      </Paper>
    </Container>
  );
}
